sys_script_fix.script:
// AIROP Post-Install Fix Script
// Flushes cache to activate cross-scope access privileges
// Must run after install on any new instance

gs.info('[AIROP] Post-install fix script running...');

try {
    var cache = new GlideCacheManager();
    cache.flushAll();
    gs.info('[AIROP] Cache flushed successfully - scope privileges now active');
} catch(e) {
    // Fallback method
    gs.info('[AIROP] Trying alternate cache flush method...');
    GlideCache.flushAll();
    gs.info('[AIROP] Cache flushed via alternate method');
}
